const metrics = {
  leads_active: $input.all()[0].json.filter(r => !['completed','disqualified'].includes(r.status)).reduce((s,r) => s + Number(r.count), 0),
  emails_sent: $input.all()[1].json.filter(r => r.event_type === 'sent').reduce((s,r) => s + Number(r.count), 0),
  replies_total: $input.all()[2].json.reduce((s,r) => s + Number(r.count), 0),
  positive_replies: $input.all()[2].json.filter(r => ['interested','needs_more_info','pricing_question'].includes(r.reply_type)).reduce((s,r) => s + Number(r.count), 0),
  meetings_booked: $input.all()[0].json.filter(r => r.status === 'booked').reduce((s,r) => s + Number(r.count), 0),
  sla_risks: $input.all()[3].json.reduce((s,r) => s + Number(r.count), 0),
  date: new Date().toISOString().split('T')[0]
};
return [{json: metrics}];
